int read()

{

	int num = 0;

	char c = getchar();

	while (c < '0' || c>'9')c = getchar();

	while (c >= '0' && c <= '9')num = num * 10 + c - '0', c = getchar();

	return num;

}

int dfs1(int w, int f)

{

	sz[w] = 1;

	for(int i=e[w].size()-1;i>=0;i--)

		if (e[w][i] != f)

		{

			fa[e[w][i]] = w;

			dep[e[w][i]] = dep[w] + 1;

			dfs1(e[w][i], w);

			sz[w] += sz[e[w][i]];

			if (sz[e[w][i]] > sz[hvs[w]])hvs[w] = e[w][i];

		}

	return 0;

}

int dfs2(int w, int top)

{

	id[w] = ++cnt;

	pos[cnt] = w;

	tp[w] = top;

	if (hvs[w])dfs2(hvs[w], top);

